#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define MAX_N 50000
#define MAX_M 200

int maxPathValue[MAX_N];
int weights[MAX_N];
int edges[MAX_N][MAX_M];
int numEdges[MAX_N];

void dfs(int node, int depth, int *maxValue) {
    int i;
    int currentValue = depth * weights[node];
    if (currentValue > *maxValue) {
        *maxValue = currentValue;
    }
    for (i = 0; i < numEdges[node]; i++) {
        int neighbor = edges[node][i];
        dfs(neighbor, depth + 1, maxValue);
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int i;
        for (i = 0; i < N; i++) {
            scanf("%d", &weights[i]);
        }
        for (i = 0; i < N; i++) {
            numEdges[i] = 0;
        }
        for (i = 0; i < N - 1; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            u--;
            v--;
            edges[u][numEdges[u]] = v;
            numEdges[u]++;
            edges[v][numEdges[v]] = u;
            numEdges[v]++;
        }
        int maxValue = INT_MIN;
        dfs(0, 1, &maxValue);
        printf("%d\n", maxValue);
    }
    return 0;
}

